+        let mut parser = IngestParser::with_defaults();
+        parser.feed(b"test line\n");
+        let entry = parser.log_entry();
+        assert_eq!(entry.total_lines, 1);
+        assert_eq!(entry.degradation, IngestDegradation::Healthy);
+    }
