+        let variants = vec![
+            IngestDegradation::Healthy,
+            IngestDegradation::HighBufferPressure { buffered_bytes: 100, max_line_bytes: 120 },
+            IngestDegradation::DataCorruption { invalid_bytes: 10, total_bytes: 200 },
